};

const MessageBus = {
  subscribers: {},
  async publish(event) {
    (this.subscribers[event.type] || []).forEach(fn => fn(event));
  },
  subscribe(type, fn) {
    this.subscribers[type] = this.subscribers[type] || [];
    this.subscribers[type].push(fn);
  }
};

// Command handler
async function placeOrder(cmd) {
  const event = { type: 'OrderPlaced', orderId: cmd.orderId, total: cmd.total, ts: Date.now() };
  await EventStore.append('orders-' + cmd.orderId, event);
  await MessageBus.publish(event);
  return { status: 'accepted' };
}

